#!/usr/bin/env python3
import re
import sys

def parse_ping_output(output):
    # Extract the summary line with RTT stats
    lines = output.strip().split('\n')
    for line in reversed(lines):
        if 'rtt min/avg/max/mdev' in line:
            parts = line.split('/')
            avg_rtt = float(parts[1])
            return avg_rtt
        elif 'packets transmitted, received, loss' in line:
            match = re.search(r'(\d+) packets transmitted, (\d+) received, (\d+)% packet loss', line)
            if match:
                tx, rx, loss_percent = map(int, match.groups())
                loss_ratio = loss_percent / 100.0
                return None, loss_ratio
    return None, None

def main():
    result = subprocess.run(['ping', '-c', '10', 'google.com'], capture_output=True, text=True)
    if result.returncode != 0:
        print("Ping failed.")
        sys.exit(1)

    avg_rtt, loss_ratio = parse_ping_output(result.stdout)

    if avg_rtt is not None:
        print(f"Average RTT: {avg_rtt:.2f} ms")
        if avg_rtt >= 500:
            print("FAIL: Average latency exceeds 500ms")
            sys.exit(1)
        else:
            print("PASS: Average latency within acceptable bounds")

    if loss_ratio is not None:
        print(f"Packet loss: {loss_ratio * 100:.2f}%")
        if loss_ratio >= 0.10:
            print("FAIL: Packet loss >= 10%")
            sys.exit(1)
        else:
            print("PASS: Packet loss is low (< 10%)")

if __name__ == "__main__":
    import subprocess
    main()
